class Solution:
    def popcountDepth(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        n = len(nums)
        max_depth = 5

        def depth(x):
            d = 0
            while x != 1:
                x = bin(x).count('1')
                d += 1
            return d

        depths = [depth(nums[i]) for i in range(n)]

        class FenwickTree:
            def __init__(self, size, max_depth):
                self.size = size
                self.max_depth = max_depth
                self.tree = [[0]*(max_depth+1) for _ in range(size+2)]

            def update(self, idx, old_d, new_d):
                idx += 1
                while idx <= self.size:
                    self.tree[idx][old_d] -= 1
                    self.tree[idx][new_d] += 1
                    idx += idx & -idx

            def query(self, l, r, k):
                l += 1
                r += 1
                res = 0
                while r > 0:
                    res += self.tree[r][k]
                    r -= r & -r
                l -= 1
                while l > 0:
                    res -= self.tree[l][k]
                    l -= l & -l
                return res

        ft = FenwickTree(n, max_depth)
        for i in range(n):
            ft.update(i, 0, depths[i])

        res = []
        for q in queries:
            if q[0] == 1:
                l, r, k = q[1], q[2], q[3]
                if k < 0 or k > max_depth:
                    res.append(0)
                else:
                    res.append(ft.query(l, r, k))
            else:
                idx, val = q[1], q[2]
                new_d = depth(val)
                old_d = depths[idx]
                if old_d != new_d:
                    ft.update(idx, old_d, new_d)
                    depths[idx] = new_d
        return res
